import React from 'react';
import './patienttable.css';

// 1. Accept 'patients' as a prop
const PatientTable = ({ patients = [] }) => {
    
    return (
        <div className="table-wrapper">
            <div className="table-title-area">
                <h3>Recent Patient Admissions</h3>
                <div className="table-actions">
                    <input type="text" placeholder="Filter by name..." className="table-search" />
                </div>
            </div>
            
            <table className="patient-table">
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Patient Name</th>
                        <th>Age / Gender</th>
                        <th>Contact</th> {/* Changed to match your form */}
                        <th className="status-col">Status</th>
                        <th>Action</th>
                    </tr>
                </thead>
                <tbody>
                    {/* 2. Check if patients exist, then map */}
                    {patients.length > 0 ? (
                        patients.map((patient) => (
                            <tr key={patient._id}> {/* MongoDB uses _id */}
                                <td className="id-col">
                                    {/* Show last 4 digits of MongoDB ID for a cleaner look */}
                                    #{patient._id.slice(-4).toUpperCase()}
                                </td>
                                <td className="name-col">{patient.name}</td>
                                <td>{patient.age} / {patient.gender}</td>
                                <td>{patient.contact}</td>
                                <td className="status-col">
                                    <span className={`badge ${(patient.status || 'admitted').toLowerCase()}`}>
                                        {patient.status || 'Admitted'}
                                    </span>
                                </td>
                                <td>
                                    <button className="action-dots">⋮</button>
                                </td>
                            </tr>
                        ))
                    ) : (
                        <tr>
                            <td colSpan="6" style={{ textAlign: 'center', padding: '20px' }}>
                                No patients found in database.
                            </td>
                        </tr>
                    )}
                </tbody>
            </table>
        </div>
    );
};

export default PatientTable;
